        var sStartTime;
        this.fnExecute = function(obj,e)
        {
        	var objDate = new Date();
        	sStartTime = objDate.getTime();

        	if(this.divLayOut.form.Tab00.tabindex == 0)
        	{
        		//Dataset enableevent=true(default)
        		var nRow;
        		var nRowCnt = this.Dataset00.rowcount;
        		var nColCnt = this.Dataset00.colcount;

        		this.Dataset01.clearData();
        		for(var i=0;i<nRowCnt;i++)
        		{
        			nRow = this.Dataset01.addRow();
        			for(var j=0;j<nColCnt;j++)
        			{
        				this.Dataset01.setColumn(nRow, j, this.Dataset00.getColumn(i, j));
        			}
        		}
        	} else {
        		var nRow;
        		var nRowCnt = this.Dataset00.rowcount;
        		var nColCnt = this.Dataset00.colcount;

        		this.Dataset02.enableevent = false; /* enableevent=false */

        		 this.Dataset02.clearData();
        		for(var i=0;i<nRowCnt;i++)
        		{
        			nRow = this.Dataset02.addRow();
        			for(var j=0;j<nColCnt;j++)
        			{
        				this.Dataset02.setColumn(nRow, j, this.Dataset00.getColumn(i, j));
        			}
        		}
        		this.Dataset02.enableevent = true; /* enableevent=true */
        	}
        	objDate = new Date();
        	this.divLayOut.form.mk_time.value = (objDate.getTime()-sStartTime)/1000;
        };

